# Generated by Gemini Pro

import matplotlib.pyplot as plt

def plot_bar_chart():
    # Data from your final calculated metrics
    comparisons = [
        'Stage 1 vs Base\n(Alpaca / General)', 
        'Stage 2 vs Stage 1\n(Alpaca / General)', 
        'Stage 2 vs Stage 1\n(JSON / Structured)'
    ]
    
    # Your exact win rates
    win_rates = [26.3, 47.5, 28.2]
    
    # Professional colors for the bars
    colors = ['#1f77b4', '#2ca02c', '#ff7f0e']

    print("Generating LLM-as-a-Judge Win Rate bar chart...")
    plt.figure(figsize=(9, 6))
    
    # Create the bars
    bars = plt.bar(comparisons, win_rates, color=colors, width=0.5, edgecolor='black', alpha=0.85)

    # Add the percentage text exactly on top of each bar
    for bar in bars:
        yval = bar.get_height()
        plt.text(bar.get_x() + bar.get_width()/2, yval + 1.5, f"{yval}%", 
                 ha='center', va='bottom', fontweight='bold', fontsize=12)

    # Formatting the chart
    plt.title('LLM-as-a-Judge: Win Rates Across Checkpoints', fontsize=15, fontweight='bold', pad=15)
    plt.ylabel('Judge Preference / Win Rate (%)', fontsize=12, fontweight='bold')
    plt.ylim(0, 100)  # Keep Y axis 0-100 to show true percentage scale
    plt.grid(axis='y', linestyle='--', alpha=0.6)

    # Save the figure
    output_path = 'judge_win_rates.png'
    plt.tight_layout()
    plt.savefig(output_path, dpi=300)
    plt.close()
    
    print(f"Success! Bar chart saved to {output_path}")

if __name__ == "__main__":
    plot_bar_chart()